    private uint _physicalOperatorIdCounter;
    private readonly Main.BogDatabase _database;

    public PlanMapper(Main.BogDatabase database = null)
    {
        _physicalOperatorIdCounter = 0;
        _database = database;
    }

    public PhysicalPlan MapLogicalPlanToPhysical(LogicalPlan logicalPlan)
    {
        var physicalRoot = MapOperator(logicalPlan.LastOperator);
        return new PhysicalPlan(physicalRoot);
    }

    private PhysicalOperator MapOperator(LogicalOperator logicalOperator)
    {
        switch (logicalOperator.OperatorType)
        {
            case LogicalOperatorType.LOGICAL_SCAN_NODE:
                return MapLogicalScanNodeToPhysical((LogicalScanNodeProperty)logicalOperator);
            case LogicalOperatorType.LOGICAL_FILTER:
                return MapLogicalFilterToPhysical((LogicalFilter)logicalOperator);
            case LogicalOperatorType.LOGICAL_PROJECTION:
                return MapLogicalProjectionToPhysical((LogicalProjection)logicalOperator);
            case LogicalOperatorType.LOGICAL_EXTEND:
                return MapLogicalTraverseRelToPhysical((LogicalTraverseRel)logicalOperator);
            case LogicalOperatorType.LOGICAL_HASH_JOIN:
                return MapLogicalHashJoinToPhysical((LogicalValueJoin)logicalOperator);
            case LogicalOperatorType.LOGICAL_CROSS_PRODUCT:
                return MapLogicalCrossProductToPhysical((LogicalNestedLoopJoin)logicalOperator);
            case LogicalOperatorType.LOGICAL_OPTIONAL_JOIN:
                return MapLogicalOptionalJoinToPhysical((LogicalOptionalJoin)logicalOperator);
            case LogicalOperatorType.LOGICAL_RECURSIVE_EXTEND:
                return MapLogicalRecursiveExtendToPhysical((LogicalRecursiveExtend)logicalOperator);
            case LogicalOperatorType.LOGICAL_COPY_FROM:
                return MapLogicalCopyFromToPhysical((LogicalCopyFrom)logicalOperator);
            case LogicalOperatorType.LOGICAL_COPY_TO:
                return MapLogicalCopyToToPhysical((LogicalCopyTo)logicalOperator);
            case LogicalOperatorType.LOGICAL_ATTACH_DATABASE:
                return MapLogicalAttachDatabaseToPhysical((LogicalAttachDatabase)logicalOperator);
            case LogicalOperatorType.LOGICAL_EXTENSION:
                return MapLogicalExtensionToPhysical((LogicalExtensionStatement)logicalOperator);
            case LogicalOperatorType.LOGICAL_CREATE_MACRO:
                return MapLogicalCreateMacroToPhysical((LogicalCreateMacro)logicalOperator);
            case LogicalOperatorType.LOGICAL_LIMIT:
                return MapLogicalLimitToPhysical((LogicalLimit)logicalOperator);
            case LogicalOperatorType.LOGICAL_SKIP:
                return MapLogicalSkipToPhysical((LogicalSkip)logicalOperator);
            case LogicalOperatorType.LOGICAL_ORDER_BY:
                return MapLogicalOrderByToPhysical((LogicalOrderBy)logicalOperator);
            case LogicalOperatorType.LOGICAL_TOP_K:
                return MapLogicalTopKToPhysical((Planner.Operator.LogicalTopK)logicalOperator);
            case LogicalOperatorType.LOGICAL_INSERT:
                return MapLogicalInsertToPhysical((LogicalInsert)logicalOperator);
            case LogicalOperatorType.TABLE_FUNCTION_CALL:
                return MapLogicalTableFunctionCallToPhysical((LogicalTableFunctionCall)logicalOperator);
            case LogicalOperatorType.LOGICAL_SET_NODE_PROPERTY:
                return MapLogicalSetNodePropertyToPhysical((LogicalSetNodeProperty)logicalOperator);
            case LogicalOperatorType.LOGICAL_SET_REL_PROPERTY:
                // Mapping rel property sets to the exact same logic flow since dummy mappings are naive dictionaries right now
                return MapLogicalSetRelPropertyToPhysical((LogicalSetRelProperty)logicalOperator);
            case LogicalOperatorType.LOGICAL_MERGE_NODE:
                return MapLogicalMergeNodeToPhysical((LogicalMergeNode)logicalOperator);
            case LogicalOperatorType.LOGICAL_MERGE_REL:
                return MapLogicalMergeRelToPhysical((LogicalMergeRel)logicalOperator);
            case LogicalOperatorType.LOGICAL_MERGE_GRAPH:
                return MapLogicalMergeGraphToPhysical((LogicalMergeGraph)logicalOperator);
            case LogicalOperatorType.LOGICAL_DELETE_NODE:
                return MapLogicalDeleteNodeToPhysical((LogicalDeleteNode)logicalOperator);
            case LogicalOperatorType.LOGICAL_DELETE_REL:
                return MapLogicalDeleteRelToPhysical((LogicalDeleteRel)logicalOperator);
            case LogicalOperatorType.LOGICAL_SINGLE_ROW:
                return new BogDb.Core.Processor.Operator.Scan.SingleRowPhysicalOperator(GetNextOperatorID());
            case LogicalOperatorType.LOGICAL_UNWIND:
                return MapLogicalUnwindToPhysical((LogicalUnwind)logicalOperator);
            case LogicalOperatorType.LOGICAL_AGGREGATE:
                return MapLogicalAggregateToPhysical((LogicalAggregate)logicalOperator);
            case LogicalOperatorType.LOGICAL_DISTINCT:
                return MapLogicalDistinctToPhysical(logicalOperator);
            case LogicalOperatorType.LOGICAL_FLATTEN:
                return MapLogicalFlattenToPhysical(logicalOperator);
            case LogicalOperatorType.LOGICAL_UNION_ALL:
                return MapLogicalUnionAllToPhysical(logicalOperator);
            case LogicalOperatorType.LOGICAL_EXPRESSIONS_SCAN:
                return MapLogicalExpressionsScanToPhysical(logicalOperator);
            case LogicalOperatorType.LOGICAL_ACCUMULATE:
                return MapLogicalAccumulateToPhysical((Planner.Operator.LogicalAccumulate)logicalOperator);
            case LogicalOperatorType.LOGICAL_CREATE_NODE:
                return MapLogicalInsertToPhysical((LogicalInsert)logicalOperator);
            case LogicalOperatorType.LOGICAL_CREATE_REL:
                return MapLogicalInsertToPhysical((LogicalInsert)logicalOperator);
            case LogicalOperatorType.LOGICAL_STANDALONE_CALL:
                return MapLogicalStandaloneCallToPhysical((LogicalStandaloneCall)logicalOperator);
            case LogicalOperatorType.LOGICAL_IN_QUERY_CALL:
                return new BogDb.Core.Processor.Operator.Scan.SingleRowPhysicalOperator(GetNextOperatorID());
            case LogicalOperatorType.LOGICAL_INDEX_SCAN_NODE:
                return MapLogicalIndexScanNodeToPhysical((BogDb.Core.Planner.LogicalIndexScanNode)logicalOperator);
            case LogicalOperatorType.LOGICAL_EXTERNAL_INDEX_SCAN_NODE:
                return MapLogicalExternalIndexScanNodeToPhysical((BogDb.Core.Planner.LogicalExternalIndexScanNode)logicalOperator);
            case LogicalOperatorType.LOGICAL_PROFILE:
                return MapLogicalProfileToPhysical(logicalOperator);
            case LogicalOperatorType.LOGICAL_SEMI_MASKER:
                return MapLogicalSemiMaskerToPhysical((Planner.Operator.Sip.LogicalSemiMasker)logicalOperator);
            case LogicalOperatorType.LOGICAL_SCAN_FRONTIER:
                return MapLogicalScanFrontierToPhysical((Planner.Operator.LogicalScanFrontier)logicalOperator);
            case LogicalOperatorType.LOGICAL_INTERSECT:
                return MapUnsupportedLogicalOperatorToPhysical(logicalOperator); // Placeholder — full intersect planning is a planner-parity item
            case LogicalOperatorType.LOGICAL_MARK_JOIN:
                return MapLogicalMarkJoinToPhysical((Planner.Operator.LogicalMarkJoin)logicalOperator);
            case LogicalOperatorType.LOGICAL_CALL_SUBQUERY:
                return MapLogicalCallSubqueryToPhysical((Planner.Operator.LogicalCallSubquery)logicalOperator);
            default:
                return MapUnsupportedLogicalOperatorToPhysical(logicalOperator);
        }
    }

    private PhysicalOperator MapUnsupportedLogicalOperatorToPhysical(LogicalOperator logicalOperator)
    {
        // Keep execution resilient for logical operators that are declared in the enum
        // but not yet fully mapped in the C# physical layer.
        if (!logicalOperator.HasChild())
        {
            return new NoOpPhysicalOperator(GetNextOperatorID());
        }

        if (logicalOperator.GetNumChildren() == 1)
        {
            return MapOperator(logicalOperator.GetChild(0));
        }

        // Multi-child unsupported operators degrade to a no-op sink to avoid
        // producing incorrect cross-operator semantics silently.
        return new NoOpPhysicalOperator(GetNextOperatorID());
    }

    private PhysicalOperator MapLogicalCopyFromToPhysical(LogicalCopyFrom logicalOperator)
    {
        var tableEntry = _database?.Catalog.GetTableEntry(logicalOperator.TableName);
        var isRelTable = tableEntry is BogDb.Core.Catalog.RelGroupCatalogEntry
                         || (_database != null && _database.RelTables.ContainsKey(logicalOperator.TableName));
        if (isRelTable)
        {
            return new BogDb.Core.Processor.Operator.Persistent.CopyRel(
                logicalOperator.TableName,
                logicalOperator.FilePath,
                logicalOperator.ColumnOrder,
                _database,
                GetNextOperatorID());
        }

        var propertyNames = new System.Collections.Generic.List<string>(logicalOperator.ColumnOrder);
        var propertyTypes = ResolveCopyColumnTypes(tableEntry as CatalogModel.TableCatalogEntry, logicalOperator.ColumnOrder);
        var primaryKeyPropertyName = ResolvePrimaryKeyPropertyName(tableEntry as CatalogModel.NodeTableCatalogEntry);

        return new BogDb.Core.Processor.Operator.Persistent.CopyNode(
            logicalOperator.TableName, 
            logicalOperator.FilePath,
            _database, // We will inject database safely at query execution.
            propertyNames,
            propertyTypes,
            primaryKeyPropertyName,
            GetNextOperatorID());
    }

