    }

    private static List<Common.LogicalTypeID> ResolveCopyColumnTypes(
        CatalogModel.TableCatalogEntry? tableEntry,
        IReadOnlyList<string> columnOrder)
    {
        if (tableEntry == null)
            return new List<Common.LogicalTypeID>();

        var typesByName = new Dictionary<string, Common.LogicalTypeID>(StringComparer.OrdinalIgnoreCase);
        foreach (var property in tableEntry.GetProperties())
            typesByName[property.ColumnDef.Name] = property.ColumnDef.Type;

        var types = new List<Common.LogicalTypeID>(columnOrder.Count);
        foreach (var column in columnOrder)
        {
            if (typesByName.TryGetValue(column, out var type))
                types.Add(type);
            else
                types.Add(Common.LogicalTypeID.STRING);
        }

        return types;
    }

    private static string ResolvePrimaryKeyPropertyName(CatalogModel.NodeTableCatalogEntry? entry)
    {
        if (entry == null)
            return "id";

        foreach (var property in entry.GetProperties())
        {
            if (entry.GetPropertyID(property.ColumnDef.Name) == entry.PrimaryKeyPropertyID)
                return property.ColumnDef.Name;
        }

        return "id";
    }

