    private PhysicalOperator MapLogicalTableFunctionCallToPhysical(LogicalTableFunctionCall logicalOperator)
    {
        PhysicalOperator? child = null;
        if (logicalOperator.HasChild())
        {
            var logicalChild = logicalOperator.GetChild(0);
            child = logicalChild != null ? MapOperator(logicalChild) : null;
        }
        return new PhysicalTableFunctionCall(
            logicalOperator.FunctionExpression,
            logicalOperator.OutVariables,
            child,
            GetNextOperatorID(),
            _database?.FunctionRegistry,
            _database?.StandaloneTableFunctionRegistry);
    }

