    }

    private PhysicalOperator MapLogicalCallSubqueryToPhysical(Planner.Operator.LogicalCallSubquery logicalOperator)
    {
        // Map the outer child (the pipeline feeding into CALL)
        var outerPhysical = logicalOperator.HasChild()
            ? MapOperator(logicalOperator.GetChild(0))
            : new Operator.Scan.SingleRowPhysicalOperator(GetNextOperatorID());

        // Map the inner plan (used for non-correlated execution)
        PhysicalOperator innerPhysical;
        if (logicalOperator.InnerPlan != null)
        {
            innerPhysical = MapLogicalPlanToPhysical(logicalOperator.InnerPlan).LastOperator;
        }
        else
        {
            innerPhysical = new NoOpPhysicalOperator(GetNextOperatorID());
        }

        return new PhysicalCallSubquery(
            outerPhysical,
            innerPhysical,
            logicalOperator.CorrelatedVariables,
            logicalOperator.IsCorrelated ? logicalOperator.CorrelatedVarInfos : null,
            logicalOperator.OutputColumnNames,
            logicalOperator.IsCorrelated ? logicalOperator.InnerQueryText : null,
            _database,
            GetNextOperatorID());
    }

    private uint GetNextOperatorID() => _physicalOperatorIdCounter++;
